import { useEffect } from 'react';

export default function Modal({ data, onClose }) {
  useEffect(() => {
    if (!data) {
      return;
    }
  
    const handleClickOutside = (event) => {
      if (event.target.closest('.modal-content') === null && !event.target.classList.contains('button-title')) {
        onClose();
      }
    };
  
    document.addEventListener('click', handleClickOutside);
    return () => {
      document.removeEventListener('click', handleClickOutside);
    };
  }, [data, onClose]);
  

  if (!data) {
    return null;
  }

  return (
    <div className="project-modal">
      <div className="modal-content">
        <h4 className="modal-title">{data.title}</h4>
        <i className="fa-solid fa-xmark modal-close" onClick={onClose}></i>

        <div className="modal-desc">
          <i className="fa-solid fa-book-open modal-icon"></i>
          <p>{data.modal}</p>
        </div>
      </div>
    </div>
  );
}
