import { useState, useEffect } from 'react'
import 'swiper/element/css/navigation'
import './projects.css'
import Carousel from './Carousel'
import Modal from './Modal'
import { useSwiper } from './useSwiper'

const Projects = () => {
  const { swiperRef, nextButtonRef, prevButtonRef } = useSwiper();
  const [swiper, updateSwiper] = useState(null);
  const [modalData, setModalData] = useState(null);

  useEffect(() => {
    if (swiper !== null) {
      swiper.navigation.update();
    }
  }, [swiper]);

  return (
    <section className="project section" id="projects">
        <h2 className="section-title"> Projects</h2>
        <span className="section-subtitle">My Recent Work</span>

        <div className="project-container container">
            <Carousel swiperRef={swiperRef} onSwiper={updateSwiper} setModalData={setModalData} />
                
            {modalData && <Modal data={modalData} onClose={() => setModalData(null)} />}
            
            <div ref={nextButtonRef} className="swiper-button-next">
                <i className="fa-solid fa-angle-right swiper-project-icon"></i>
            </div>
            <div ref={prevButtonRef} className="swiper-button-prev">
                <i className="fa-solid fa-angle-left swiper-project-icon"></i>
            </div>
        </div>
    </section>
  )
}

export default Projects
