import { useEffect } from 'react';


const Nav = ({ sections, activeSection, setActiveSection, toggle, setToggle }) => {
    const handleClick = (section) => {
        // Check if the clicked section is already the active section
        if (activeSection === section.title.toLowerCase()) {
            // If it is, simply return and don't update the activeSection state
            return;
        }
        setActiveSection(section.title);
        const element = document.getElementById(section.title.toLowerCase());
        element.scrollIntoView({ behavior: "smooth" });
        setToggle(false); //Close the nav when a link is clicked
    }
    
    useEffect(() => {
        const handleOutsideClick = (event) => {
            if (!event.target.closest('.nav-menu') && !event.target.closest('.nav-toggle')) {
                setToggle(false);
            }
        };
    
        document.addEventListener('click', handleOutsideClick);
    
        return () => {
            document.removeEventListener('click', handleOutsideClick);
        };
    }, []);

    return (
        <div className={toggle ? "nav-menu show-menu" : "nav-menu"}>
            <ul className="nav-list grid">
                {sections.map(section => (
                    <li key={section.title.toLowerCase()} className="nav-item">
                        <a
                            href={`#${section.title.toLowerCase()}`}
                            className={activeSection === section.title.toLowerCase() ?
                                "nav-link active-link" : "nav-link"}
                            onClick={() => handleClick(section)}
                        >
                            <i className={section.icon + ' nav-icon'}></i> {section.title}
                        </a>
                    </li>
                ))}
                
                <i className="fa-solid fa-xmark nav-close" onClick={() => setToggle(false)}></i>
            </ul>
        </div>
    );
}

export default Nav