import { Data } from './Data'
import ReadMore from './ReadMore';

// import function to register Swiper custom elements
import { register } from 'swiper/element/bundle';
// // register Swiper custom elements
register();

export default function Carousel({ navigation, swiperRef, setModalData }) {
    const handleReadMore = (data) => {
        setModalData(data);
    }

    return (
      <>
        <swiper-container ref={swiperRef} slidesPerView={1}
            spaceBetween={350}
            loop={true}
            pagination
            navigation={navigation}>
            {Data.map((data) => {
                return <swiper-slide key={data.id}>
                            <img src={data.image} alt={data.alt} className="project-img" />

                            <div className="project-data">
                                <div className="title-container">
                                    <h3 className="project-title">{data.title}</h3>

                                    <ReadMore onClick={() => handleReadMore(data)}/>
                                </div>
                                
                                <p className="project-desc">{data.desc}</p>

                                <a href={data.code} className="button button-flex button-small project-button">
                                    Code <i className="fa-solid fa-code button-icon"></i>
                                </a>

                                <a href={data.demo} className="button button-flex button-small project-button">
                                    Demo <i className="fa-solid fa-desktop button-icon"></i>
                                </a>
                            </div>
                        </swiper-slide>
            })}
        </swiper-container>
      </>
    )
}